const { ethers } = require('ethers');
require('dotenv').config();

const RPC_URL = process.env.RPC_URL;
const PRIVATE_KEY = process.env.PRIVATE_KEY;

if (!RPC_URL) throw new Error('Missing RPC_URL');
if (!PRIVATE_KEY) throw new Error('Missing PRIVATE_KEY');

const provider = new ethers.JsonRpcProvider(RPC_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

async function getBalance(address = wallet.address) {
  const balance = await provider.getBalance(address);
  return ethers.formatEther(balance);
}

async function sendEth(to, amountEth, options = {}) {
  if (!ethers.isAddress(to)) throw new Error('Invalid recipient address');
  const value = ethers.parseEther(String(amountEth));
  const tx = {
    to,
    value,
    gasLimit: options.gasLimit ? BigInt(options.gasLimit) : undefined,
    gasPrice: options.gasPrice ? ethers.parseUnits(String(options.gasPrice), 'gwei') : undefined,
    maxFeePerGas: options.maxFeePerGas ? ethers.parseUnits(String(options.maxFeePerGas), 'gwei') : undefined,
    maxPriorityFeePerGas: options.maxPriorityFeePerGas ? ethers.parseUnits(String(options.maxPriorityFeePerGas), 'gwei') : undefined,
    nonce: options.nonce,
    chainId: options.chainId
  };

  Object.keys(tx).forEach((k) => tx[k] === undefined && delete tx[k]);

  const sentTx = await wallet.sendTransaction(tx);
  return {
    hash: sentTx.hash,
    from: sentTx.from,
    to: sentTx.to,
    value: ethers.formatEther(sentTx.value)
  };
}

function getContract(address, abi) {
  if (!ethers.isAddress(address)) throw new Error('Invalid contract address');
  if (!Array.isArray(abi)) throw new Error('Invalid ABI');
  return new ethers.Contract(address, abi, wallet);
}

async function callContractMethod(contractAddress, abi, methodName, args = [], overrides = {}) {
  const contract = getContract(contractAddress, abi);
  if (typeof contract[methodName] !== 'function') throw new Error(`Method not found: ${methodName}`);
  return await contract[methodName](...args, overrides);
}

async function sendContractTransaction(contractAddress, abi, methodName, args = [], overrides = {}) {
  const contract = getContract(contractAddress, abi);
  if (typeof contract[methodName] !== 'function') throw new Error(`Method not found: ${methodName}`);
  const tx = await contract[methodName](...args, overrides);
  return {
    hash: tx.hash,
    nonce: tx.nonce,
    gasLimit: tx.gasLimit ? tx.gasLimit.toString() : undefined
  };
}

async function waitForTransaction(hash, confirmations = 1) {
  return await provider.waitForTransaction(hash, confirmations);
}

async function estimateEthTransferGas(to, amountEth) {
  const value = ethers.parseEther(String(amountEth));
  return await provider.estimateGas({ to, value });
}

async function estimateContractGas(contractAddress, abi, methodName, args = [], overrides = {}) {
  const contract = getContract(contractAddress, abi);
  if (typeof contract[methodName] !== 'function') throw new Error(`Method not found: ${methodName}`);
  return await contract[methodName].estimateGas(...args, overrides);
}

